import { parse } from 'https://cdn.jsdelivr.net/npm/mathjs@15/+esm';
const f = parse(expr).compile();               // expr = 用户/AI 给的表达式字符串
const pts = [];
for (let x = -10; x <= 10; x += 0.1) pts.push([x, f.evaluate({ x })]);
